  "cameraIds": [
    "string"
  ],
  "ringSettings": [
    {
      "cameraId": "string",
      "repeatTimes": 0,
      "ringtoneId": "string",
      "volume": 0
    }
  ]
});


let config = {
  method: 'patch',
  maxBodyLength: Infinity,
  url: 'https://192.168.0.1/proxy/protect/integration/v1/chimes/{id}',
  headers: { 
    'Accept': 'application/json', 
    'X-API-Key': '<X-API-Key>', 
    'Content-Type': 'application/json'
  },
  data : data
};


axios.request(config)
.then((response) => {
  console.log(JSON.stringify(response.data));
})
.catch((error) => {
  console.log(error);
});

