import http.client
import json


conn = http.client.HTTPSConnection("192.168.0.1")
payload = json.dumps({
  "name": "string",
  "cameraIds": [
    "string"
  ],
  "ringSettings": [
    {
      "cameraId": "string",
      "repeatTimes": 0,
      "ringtoneId": "string",
      "volume": 0
    }
  ]
})
headers = {
  'Accept': 'application/json',
  'X-API-Key': '<X-API-Key>',
  'Content-Type': 'application/json'
}
conn.request("PATCH", "/proxy/protect/integration/v1/chimes/{id}", payload, headers)
res = conn.getresponse()
data = res.read()
print(data.decode("utf-8"))

